package com.google.gson.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Type;
import java.lang.reflect.TypeVariable;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

class TypeTokenTest {

  @Test
  void matches_whenToEqualsFrom_returnsTrue() throws Exception {
    Type from = mock(Type.class);
    Type to = from;
    Map<String, Type> typeMap = new HashMap<>();

    // Use reflection to access private static method
    var method = TypeToken.class.getDeclaredMethod("matches", Type.class, Type.class, Map.class);
    method.setAccessible(true);

    boolean result = (boolean) method.invoke(null, from, to, typeMap);

    assertTrue(result);
  }

  @Test
  void matches_whenFromIsTypeVariableAndToEqualsMappedType_returnsTrue() throws Exception {
    @SuppressWarnings("unchecked")
    TypeVariable<?> from = mock(TypeVariable.class);
    Type to = mock(Type.class);
    Map<String, Type> typeMap = new HashMap<>();

    when(from.getName()).thenReturn("T");
    typeMap.put("T", to);

    // Use reflection to access private static method
    var method = TypeToken.class.getDeclaredMethod("matches", Type.class, Type.class, Map.class);
    method.setAccessible(true);

    boolean result = (boolean) method.invoke(null, from, to, typeMap);

    assertTrue(result);
  }

  @Test
  void matches_whenFromIsTypeVariableAndToNotEqualsMappedType_returnsFalse() throws Exception {
    @SuppressWarnings("unchecked")
    TypeVariable<?> from = mock(TypeVariable.class);
    Type to = mock(Type.class);
    Type other = mock(Type.class);
    Map<String, Type> typeMap = new HashMap<>();

    when(from.getName()).thenReturn("T");
    typeMap.put("T", other);

    // Use reflection to access private static method
    var method = TypeToken.class.getDeclaredMethod("matches", Type.class, Type.class, Map.class);
    method.setAccessible(true);

    boolean result = (boolean) method.invoke(null, from, to, typeMap);

    assertFalse(result);
  }

  @Test
  void matches_whenFromIsNotTypeVariableAndNotEqualsTo_returnsFalse() throws Exception {
    Type from = mock(Type.class);
    Type to = mock(Type.class);
    Map<String, Type> typeMap = new HashMap<>();

    // Remove the incorrect stubbing of to.equals(from) which caused the error.

    // Use reflection to access private static method
    var method = TypeToken.class.getDeclaredMethod("matches", Type.class, Type.class, Map.class);
    method.setAccessible(true);

    boolean result = (boolean) method.invoke(null, from, to, typeMap);

    assertFalse(result);
  }
}
